import type { APIGatewayProxyEvent } from 'aws-lambda';
import en from '../locales/en.json';
import zh from '../locales/zh.json';

/**
 * Locale codes supported by the shared common dictionary.
 */
export type SupportedLocale = 'en' | 'zh';

/**
 * Nested dictionary loaded from a locale JSON file.
 */
export type TranslationDictionary = Record<string, unknown>;

/**
 * Locale-keyed dictionaries supplied by one domain Lambda.
 *
 * Domain dictionaries are merged over the shared common dictionary, so
 * domain-specific keys are available while common fallback keys remain present.
 */
export type TranslationDictionaries = Partial<Record<SupportedLocale, TranslationDictionary>>;

/**
 * Supported locale list used by locale normalization and documentation.
 */
export const SUPPORTED_LOCALES: SupportedLocale[] = ['en', 'zh'];

/**
 * Default locale when no request locale can be derived.
 */
export const FALLBACK_LOCALE: SupportedLocale = 'en';

const dictionaries: Record<SupportedLocale, TranslationDictionary> = {
  en,
  zh,
};

const mergedDictionaryCache = new WeakMap<TranslationDictionaries, Partial<Record<SupportedLocale, TranslationDictionary>>>();

/**
 * Deeply merges two translation dictionaries.
 *
 * Domain values override common values. Nested objects are merged so a domain
 * can add `petProfile.*` keys without replacing the shared `common.*` block.
 *
 * @param base - Base dictionary, usually shared common translations.
 * @param override - Domain dictionary to merge on top.
 * @returns A new merged dictionary.
 */
function mergeTranslationDictionary(
  base: TranslationDictionary,
  override: TranslationDictionary
): TranslationDictionary {
  const merged: TranslationDictionary = { ...base };

  for (const [key, value] of Object.entries(override)) {
    const existing = merged[key];

    if (
      existing &&
      typeof existing === 'object' &&
      !Array.isArray(existing) &&
      value &&
      typeof value === 'object' &&
      !Array.isArray(value)
    ) {
      merged[key] = mergeTranslationDictionary(
        existing as TranslationDictionary,
        value as TranslationDictionary
      );
    } else {
      merged[key] = value;
    }
  }

  return merged;
}

/**
 * Reads a header value using common API Gateway casing variants.
 *
 * @param event - API Gateway proxy event.
 * @param name - Header name to read.
 * @returns Header value when present.
 */
function getHeaderValue(event: APIGatewayProxyEvent, name: string): string | undefined {
  const headers = event.headers || {};
  return headers[name] || headers[name.toLowerCase()] || headers[name.toUpperCase()];
}

/**
 * Extracts a language value from a Cookie header.
 *
 * Supports both `language=<locale>` and `lang=<locale>` cookie names to match
 * Stage 1 behavior.
 *
 * @param cookieHeader - Raw Cookie header value.
 * @returns Requested locale string when present.
 */
function parseCookieLanguage(cookieHeader: string | undefined): string | undefined {
  if (!cookieHeader) {
    return undefined;
  }

  const languageCookie = cookieHeader
    .split(';')
    .map((part) => part.trim())
    .find((part) => part.startsWith('language=') || part.startsWith('lang='));

  return languageCookie?.split('=').slice(1).join('=');
}

/**
 * Normalizes raw locale input to a supported shared locale.
 *
 * Chinese variants such as `zh-HK` and `zh_TW` resolve to `zh`; English
 * variants resolve to `en`.
 *
 * @param value - Raw locale value from query, cookie, header, or caller input.
 * @param fallback - Locale to use when the value is missing or unsupported.
 * @returns Supported locale code.
 */
export function normalizeLocale(value: unknown, fallback: SupportedLocale = FALLBACK_LOCALE): SupportedLocale {
  if (value === undefined || value === null || value === '') {
    return fallback;
  }

  const normalized = String(value).trim().toLowerCase().replace('_', '-');

  if (normalized.startsWith('zh')) {
    return 'zh';
  }

  if (normalized.startsWith('en')) {
    return 'en';
  }

  return fallback;
}

/**
 * Determines the request locale from query string, cookie, or Accept-Language.
 *
 * Priority is `?lang`/`?locale`, then `language`/`lang` cookie, then the first
 * `Accept-Language` value.
 *
 * @param event - API Gateway proxy event.
 * @param fallback - Locale to use when no supported locale is requested.
 * @returns Supported locale code.
 */
export function getRequestLocale(
  event: APIGatewayProxyEvent,
  fallback: SupportedLocale = FALLBACK_LOCALE
): SupportedLocale {
  const queryLocale = event.queryStringParameters?.lang || event.queryStringParameters?.locale;
  const cookieLocale = parseCookieLanguage(getHeaderValue(event, 'cookie'));
  const acceptLanguage = getHeaderValue(event, 'accept-language')?.split(',')[0];

  return normalizeLocale(queryLocale || cookieLocale || acceptLanguage, fallback);
}

/**
 * Loads the shared common translation dictionary for a locale.
 *
 * Dictionaries are statically imported with the layer, so this does not read
 * from disk at request time.
 *
 * @param locale - Requested locale or locale-like value.
 * @returns Shared translation dictionary.
 */
export function loadCommonTranslations(locale: unknown = FALLBACK_LOCALE): TranslationDictionary {
  return dictionaries[normalizeLocale(locale)];
}

/**
 * Loads shared common translations merged with optional domain translations.
 *
 * Domain dictionaries are expected to be statically imported by the Lambda and
 * passed into shared helpers. The merged result is cached by domain dictionary
 * object identity for warm Lambda containers.
 *
 * @param locale - Requested locale or locale-like value.
 * @param domainTranslations - Optional domain-specific dictionaries.
 * @returns Shared common dictionary, or common + domain merged dictionary.
 */
export function loadTranslations(
  locale: unknown = FALLBACK_LOCALE,
  domainTranslations?: TranslationDictionaries
): TranslationDictionary {
  const normalizedLocale = normalizeLocale(locale);
  const commonTranslations = loadCommonTranslations(normalizedLocale);
  const domainDictionary = domainTranslations?.[normalizedLocale];

  if (!domainTranslations || !domainDictionary) {
    return commonTranslations;
  }

  let cachedByLocale = mergedDictionaryCache.get(domainTranslations);
  if (!cachedByLocale) {
    cachedByLocale = {};
    mergedDictionaryCache.set(domainTranslations, cachedByLocale);
  }

  if (!cachedByLocale[normalizedLocale]) {
    cachedByLocale[normalizedLocale] = mergeTranslationDictionary(commonTranslations, domainDictionary);
  }

  return cachedByLocale[normalizedLocale];
}

/**
 * Resolves a dotted translation key from a dictionary.
 *
 * @param translations - Translation dictionary to search.
 * @param key - Dotted key such as `common.unauthorized`.
 * @param fallback - Value to return when the key is not found.
 * @returns Translated string, fallback, or the key itself.
 */
export function getTranslation(
  translations: TranslationDictionary,
  key: string,
  fallback?: string
): string {
  const value = key.split('.').reduce<unknown>((current, part) => {
    if (current && typeof current === 'object' && part in current) {
      return (current as Record<string, unknown>)[part];
    }

    return undefined;
  }, translations);

  return typeof value === 'string' ? value : fallback || key;
}

/**
 * Translates a key from the shared common dictionaries.
 *
 * @param key - Dotted translation key.
 * @param locale - Requested locale or locale-like value.
 * @param fallback - Value to return when the key is not found.
 * @returns Translated string, fallback, or the key itself.
 */
export function translate(
  key: string,
  locale: unknown = FALLBACK_LOCALE,
  fallback?: string,
  domainTranslations?: TranslationDictionaries
): string {
  return getTranslation(loadTranslations(locale, domainTranslations), key, fallback);
}

/**
 * Creates a small translator function bound to one locale.
 *
 * @param locale - Requested locale or locale-like value.
 * @returns Function that translates dotted keys with the bound locale.
 */
export function createTranslator(
  locale: unknown = FALLBACK_LOCALE,
  domainTranslations?: TranslationDictionaries
) {
  const translations = loadTranslations(locale, domainTranslations);

  return function t(key: string, fallback?: string): string {
    return getTranslation(translations, key, fallback);
  };
}
